#include <iostream>

int main()
{
    int n;
    std::cin >> n;

    int pass = 0;
    int fail = 0;
    int sum  = 0;

    for (int i = 0; i < n; ++i)
    {
        int score;
        std::cin >> score;
        sum += score;

        if (score >= 60)
            ++pass;
        else
            fail++;
    }

    std::cout << "Pass: "      << pass        << '\n';
    std::cout << "Fail: "      << fail        << '\n';
    std::cout << "Average: "   << sum / n     << '\n';
    std::cout << "Remainder: " << sum % n     << '\n';

    return 0;
}
